module RefModule (
    input wire clk,
    input wire reset,
    output reg [1:0] count
);
    reg [1:0] unused_next_count;

    always @(*) begin
        if (reset) begin
            unused_next_count = 2'b00;
        end else begin
            case (count)
                2'b00: unused_next_count = 2'b01;
                2'b01: unused_next_count = 2'b10;
                2'b10: unused_next_count = 2'b11;
                2'b11: unused_next_count = 2'b00;
                default: unused_next_count = 2'b00;
            endcase
        end
    end

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            count <= 2'b00;
        end else begin
            count <= unused_next_count;
        end
    end
endmodule
